/// the session's effective customizations). Consumers resolve the agent's
/// display name by looking up `uri` in the session's customization tree.
///
/// A message with no `agent` selected uses the provider's default behavior.</summary>
public sealed record AgentSelection
{
    /// <summary>Stable agent URI (matches an {@link AgentCustomization.uri}).</summary>
    public required string Uri { get; init; }
}

/// <summary>A JSON Schema-compatible property descriptor with display extensions.
///
/// Standard JSON Schema fields (`type`, `title`, `description`, `default`,
/// `enum`) allow validators to process the schema. Display extensions
/// (`enumLabels`, `enumDescriptions`) are parallel arrays that provide UI
/// metadata for each `enum` value.
///
/// This is the generic base type. See {@link SessionConfigPropertySchema} for
/// session-specific extensions.</summary>
public sealed record ConfigPropertySchema
{
    /// <summary>JSON Schema: property type</summary>
    public required string Type { get; init; }

    /// <summary>JSON Schema: human-readable label for the property</summary>
    public required string Title { get; init; }

    /// <summary>JSON Schema: description / tooltip</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public string? Description { get; init; }

    /// <summary>JSON Schema: default value</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public JsonElement? Default { get; init; }

    /// <summary>JSON Schema: allowed values. May be primitives of any JSON type.</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public List<JsonElement>? Enum { get; init; }

    /// <summary>Display extension: human-readable label per enum value (parallel array)</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public List<string>? EnumLabels { get; init; }

    /// <summary>Display extension: description per enum value (parallel array)</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public List<string>? EnumDescriptions { get; init; }

    /// <summary>JSON Schema: when `true`, the property is displayed but cannot be modified by the user</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public bool? ReadOnly { get; init; }

    /// <summary>JSON Schema: schema for array items (used when `type` is `'array'`)</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public ConfigPropertySchema? Items { get; init; }

    /// <summary>JSON Schema: property descriptors for object properties (used when `type` is `'object'`)</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public Dictionary<string, ConfigPropertySchema>? Properties { get; init; }

    /// <summary>JSON Schema: list of required property ids (used when `type` is `'object'`)</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public List<string>? Required { get; init; }

    /// <summary>JSON Schema: schema for additional properties not listed in `properties` (used when `type` is `'object'`).</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public ConfigPropertySchema? AdditionalProperties { get; init; }
}

/// <summary>A JSON Schema object describing available configuration properties.
///
/// This is the generic base type. See {@link SessionConfigSchema} for
/// session-specific usage.</summary>
public sealed record ConfigSchema
{
    /// <summary>JSON Schema: always `'object'`</summary>
    public required string Type { get; init; }

    /// <summary>JSON Schema: property descriptors keyed by property id</summary>
    public required Dictionary<string, ConfigPropertySchema> Properties { get; init; }

    /// <summary>JSON Schema: list of required property ids</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public List<string>? Required { get; init; }
}

/// <summary>A message queued for future delivery to the agent.
///
/// Steering messages are injected into the current turn mid-flight.
/// Queued messages are automatically started as new turns after the
/// current turn naturally finishes.</summary>
public sealed record PendingMessage
{
    /// <summary>Unique identifier for this pending message</summary>
    public required string Id { get; init; }

    /// <summary>The message that will start the next turn</summary>
    public required Message Message { get; init; }
}

/// <summary>Lightweight catalog entry for a chat, carried in
/// {@link SessionState.chats | `SessionState.chats`}. The full conversation
/// lives in {@link ChatState}, which inlines (denormalizes) every field below.</summary>
public sealed class ChatSummary
{
    /// <summary>Chat URI</summary>
    public required string Resource { get; set; }

    /// <summary>Chat title</summary>
    public required string Title { get; set; }

    /// <summary>Current chat status (reuses SessionStatus shape)</summary>
    public SessionStatus Status { get; set; }

    /// <summary>Human-readable description of what the chat is currently doing</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public string? Activity { get; set; }

    /// <summary>Last modification timestamp (ISO 8601, e.g. `"2025-03-10T18:42:03.123Z"`)</summary>
    public required string ModifiedAt { get; set; }

    /// <summary>How this chat came into existence</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public ChatOrigin? Origin { get; set; }

    /// <summary>How the user can interact with this chat. See {@link ChatInteractivity}.
    ///
    /// Supports agent-team patterns where worker chats are read-only or hidden.
    /// Absence defaults to {@link ChatInteractivity.Full} for backward
    /// compatibility.</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public ChatInteractivity? Interactivity { get; set; }

    /// <summary>Optional per-chat working directory.
    ///
    /// If absent, the chat inherits
    /// {@link SessionSummary.workingDirectory | the session's working directory}.
    /// See {@link ChatState.workingDirectory} for usage notes.</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public string? WorkingDirectory { get; set; }
}

/// <summary>Full state for a single chat, loaded when a client subscribes to the chat's
/// URI.
///
/// The lightweight catalog representation of a chat is {@link ChatSummary},
/// carried in {@link SessionState.chats | `SessionState.chats`}. `ChatState`
/// **denormalizes** every {@link ChatSummary} field directly onto itself so
/// subscribers receive one flat object instead of having to merge a nested
/// `summary` sub-object. Producers MUST keep the two representations
/// consistent: any change to the inlined fields below SHOULD also be
/// announced on the parent session via the matching
/// {@link SessionChatUpdatedAction | `session/chatUpdated`} action.</summary>
public sealed class ChatState
{
    /// <summary>Chat URI</summary>
    public required string Resource { get; set; }

    /// <summary>Chat title</summary>
    public required string Title { get; set; }

    /// <summary>Current chat status (reuses SessionStatus shape)</summary>
    public SessionStatus Status { get; set; }

    /// <summary>Human-readable description of what the chat is currently doing</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public string? Activity { get; set; }

    /// <summary>Last modification timestamp (ISO 8601, e.g. `"2025-03-10T18:42:03.123Z"`)</summary>
    public required string ModifiedAt { get; set; }

    /// <summary>How this chat came into existence</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public ChatOrigin? Origin { get; set; }

    /// <summary>How the user can interact with this chat. See {@link ChatInteractivity}.
    ///
    /// Supports agent-team patterns where worker chats are read-only or hidden.
    /// Absence defaults to {@link ChatInteractivity.Full} for backward
    /// compatibility.</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public ChatInteractivity? Interactivity { get; set; }

    /// <summary>Optional per-chat working directory.
    ///
    /// If absent, the chat inherits
    /// {@link SessionState.workingDirectory | the session's working directory}.
    /// Hosts MAY override this for individual chats — for example, to give a
    /// subordinate chat its own git worktree so multiple chats in a session can
    /// make independent edits that the orchestrator later merges back.</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public string? WorkingDirectory { get; set; }

    /// <summary>Completed turns</summary>
    public required List<Turn> Turns { get; set; }

    /// <summary>Currently in-progress turn</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public ActiveTurn? ActiveTurn { get; set; }

    /// <summary>Message to inject into the current turn at a convenient point</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public PendingMessage? SteeringMessage { get; set; }

    /// <summary>Messages to send automatically as new turns after the current turn finishes</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public List<PendingMessage>? QueuedMessages { get; set; }

    /// <summary>Requests for user input that are currently blocking or informing chat progress</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public List<ChatInputRequest>? InputRequests { get; set; }

    /// <summary>The user's in-progress draft input for this chat — the message they are
    /// composing but have not sent yet, including its
    /// {@link Message.model | model} / {@link Message.agent | agent} selection
    /// and attachments.
    ///
    /// Clients MAY periodically sync their local input state into this field so
    /// a draft survives reloads and is visible to other clients viewing the same
    /// chat. Eager syncing is **not** required — clients SHOULD debounce and MAY
    /// sync only at convenient points. When presenting input UI for an existing
    /// chat, clients SHOULD use any `draft` to initialize their input state.
    /// Cleared (set to `undefined`) once the message is sent.</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public Message? Draft { get; set; }

    /// <summary>Additional provider-specific metadata for this chat.</summary>
    [JsonPropertyName("_meta")]
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public Dictionary<string, JsonElement>? Meta { get; set; }
}

