/// <summary>Full state for a single session, loaded when a client subscribes to the session's URI.
///
/// Inlines (denormalizes) every {@link SessionMetadata} field directly onto
/// itself so subscribers receive one flat object instead of a nested summary.
/// The lightweight catalog representation is {@link SessionSummary}, surfaced on
/// the root channel; the host keeps the two in sync via
/// `root/sessionSummaryChanged`.</summary>
public sealed class SessionState
{
    /// <summary>Agent provider ID</summary>
    public required string Provider { get; set; }

    /// <summary>Session title</summary>
    public required string Title { get; set; }

    /// <summary>Current session status</summary>
    public SessionStatus Status { get; set; }

    /// <summary>Human-readable description of what the session is currently doing</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public string? Activity { get; set; }

    /// <summary>Server-owned project for this session</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public ProjectInfo? Project { get; set; }

    /// <summary>The default working directory URI for this session. Individual chats
    /// MAY override via {@link ChatSummary.workingDirectory | their own
    /// `workingDirectory`}; this field acts as the fallback for any chat that
    /// does not.</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public string? WorkingDirectory { get; set; }

    /// <summary>Lightweight summary of this session's inline annotations channel
    /// (`ahp-session:/&lt;uuid&gt;/annotations`). Surfaced so badge UI can render
    /// annotation / entry counts without subscribing. Absent when the session
    /// does not expose an annotations channel.</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public AnnotationsSummary? Annotations { get; set; }

    /// <summary>Session initialization state</summary>
    public SessionLifecycle Lifecycle { get; set; }

    /// <summary>Error details if creation failed</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public ErrorInfo? CreationError { get; set; }

    /// <summary>Tools provided by the server (agent host) for this session</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public List<ToolDefinition>? ServerTools { get; set; }

    /// <summary>The clients currently providing tools and interactive capabilities to this
    /// session. If multiple tools or customizations are provided by the same
    /// active client, an agent host MAY deduplicate them when exposed to a model,
    /// with a preference given to the client that started the turn.
    ///
    /// Membership is host-managed: clients add (or refresh) themselves with
    /// `session/activeClientSet`, and the host removes them with
    /// `session/activeClientRemoved` when they unsubscribe, disconnect without
    /// reconnecting in time, or reconnect without resubscribing to the session.</summary>
    public required List<SessionActiveClient> ActiveClients { get; set; }

    /// <summary>Catalog of chats in this session.</summary>
    public required List<ChatSummary> Chats { get; set; }

    /// <summary>The chat that receives input when the user addresses the session without
    /// selecting a specific chat. This is a UI routing hint, not a hierarchy
    /// marker — chats remain equal peers at the protocol level. Hosts MAY change
    /// this over the session's lifetime.</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public string? DefaultChat { get; set; }

    /// <summary>Session configuration schema and current values</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public SessionConfigState? Config { get; set; }

    /// <summary>Top-level customizations active in this session.
    ///
    /// Always one of the {@link Customization} variants:
    ///
    /// - Container customizations ({@link PluginCustomization},
    ///   {@link DirectoryCustomization}) whose children — agents, skills,
    ///   prompts, rules, hooks, MCP servers — live in each container's
    ///   {@link ContainerCustomizationBase.children | `children`} array.
    /// - Top-level {@link McpServerCustomization} entries the host
    ///   surfaces directly (for example a globally-configured MCP server
    ///   that isn't bundled in a plugin or directory). MCP servers may
    ///   also appear as children of a container.
    ///
    /// Client-published plugins arrive via
    /// {@link SessionActiveClient.customizations | `activeClients[].customizations`}
    /// and the host propagates them into this list (typically with the
    /// container's `clientId` set and `children` populated). Clients
    /// publish in container shape only; bare MCP servers at the top level
    /// are server-originated.</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public List<Customization>? Customizations { get; set; }

    /// <summary>Catalogue of changesets the server can produce for this session. Each
    /// entry advertises a subscribable view of file changes (uncommitted,
    /// session-wide, per-turn, etc.) and the URI template the client expands
    /// before subscribing. See {@link Changeset} for the full shape and
    /// {@link /guide/changesets | Changesets} for an overview of the model.</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public List<Changeset>? Changesets { get; set; }

    /// <summary>Additional provider-specific metadata for this session.
    ///
    /// Clients MAY look for well-known keys here to provide enhanced UI.
    /// For example, a `git` key may provide extra git metadata about the session's
    /// workingDirectory.</summary>
    [JsonPropertyName("_meta")]
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public Dictionary<string, JsonElement>? Meta { get; set; }
}

/// <summary>A client currently providing tools and interactive capabilities to a session.
///
/// A session MAY have several active clients at once; entries in
/// {@link SessionState.activeClients} are keyed by `clientId`. The server SHOULD
/// automatically remove an active client when that client disconnects.</summary>
public sealed class SessionActiveClient
{
    /// <summary>Client identifier (matches `clientId` from `initialize`)</summary>
    public required string ClientId { get; set; }

    /// <summary>Human-readable client name (e.g. `"VS Code"`)</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public string? DisplayName { get; set; }

    /// <summary>Tools this client provides to the session</summary>
    public required List<ToolDefinition> Tools { get; set; }

    /// <summary>Plugin customizations this client contributes to the session.
    ///
    /// Clients publish in [Open Plugins](https://open-plugins.com/) format
    /// — i.e. always container-shaped plugins. They MAY synthesize virtual
    /// plugins in memory and rely on the host to expand them into concrete
    /// children inside {@link SessionState.customizations}.</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public List<ClientPluginCustomization>? Customizations { get; set; }
}

/// <summary>Lightweight catalog entry summarizing one session. Surfaced via
/// {@link RootChannelCommands.listSessions | `root/listSessions`} and
/// `root/sessionAdded`/`root/sessionSummaryChanged` notifications.
///
/// **Aggregation across chats.** Once a session contains more than one chat,
/// several `SessionSummary` fields are derived from the underlying
/// {@link SessionState.chats | chat catalog}. Producers SHOULD follow these
/// rules so clients that only consume the session summary (e.g. a session
/// list) still see meaningful state:
///
/// - `status`: take the activity bits (`Idle` / `InProgress` / `InputNeeded` /
///   `Error` — bits 0–4) from the
///   {@link SessionState.defaultChat | default chat} when present, else from
///   the most recently modified chat. **Promote** `InputNeeded` whenever any
///   chat in the session needs input, and **promote** `Error` whenever any
///   chat is in an error state — both override the default-chat bits. The
///   orthogonal flag bits (`IsRead`, `IsArchived`) remain session-scoped.
/// - `activity`: mirror the activity string of the default chat, or of the
///   chat currently driving the promoted status bits when a non-default chat
///   wins (e.g. the chat that raised `InputNeeded`).
/// - `modifiedAt`: the max of all chats' `modifiedAt`.
/// - `workingDirectory`: the session-level **default**. Individual chats MAY
///   override via {@link ChatSummary.workingDirectory}; aggregating these up
///   is meaningless and SHOULD NOT be attempted.
/// - `changes`: optional roll-up across all chats. Producers MAY sum the
///   per-chat changeset stats or report the most expensive chat's stats —
///   whichever is cheaper for the host to compute.
///
/// Sessions with a single chat trivially satisfy all of the above (the chat's
/// values pass through unchanged). The rules only matter once a session
/// carries multiple chats.</summary>
public sealed class SessionSummary
{
    /// <summary>Agent provider ID</summary>
    public required string Provider { get; set; }

    /// <summary>Session title</summary>
    public required string Title { get; set; }

    /// <summary>Current session status</summary>
    public SessionStatus Status { get; set; }

    /// <summary>Human-readable description of what the session is currently doing</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public string? Activity { get; set; }

    /// <summary>Server-owned project for this session</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public ProjectInfo? Project { get; set; }

    /// <summary>The default working directory URI for this session. Individual chats
    /// MAY override via {@link ChatSummary.workingDirectory | their own
    /// `workingDirectory`}; this field acts as the fallback for any chat that
    /// does not.</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public string? WorkingDirectory { get; set; }

    /// <summary>Lightweight summary of this session's inline annotations channel
    /// (`ahp-session:/&lt;uuid&gt;/annotations`). Surfaced so badge UI can render
    /// annotation / entry counts without subscribing. Absent when the session
    /// does not expose an annotations channel.</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public AnnotationsSummary? Annotations { get; set; }

    /// <summary>Session URI</summary>
    public required string Resource { get; set; }

    /// <summary>Creation timestamp (ISO 8601, e.g. `"2025-03-10T18:42:03.123Z"`)</summary>
    public required string CreatedAt { get; set; }

    /// <summary>Last modification timestamp (ISO 8601, e.g. `"2025-03-10T18:42:03.123Z"`)</summary>
    public required string ModifiedAt { get; set; }

    /// <summary>Aggregate summary of file changes associated with this session. Servers
    /// may populate this to give clients a quick at-a-glance view of the
    /// session's footprint (e.g., for list rendering) without requiring the
    /// client to subscribe to a changeset.</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public ChangesSummary? Changes { get; set; }

    /// <summary>Lightweight server-defined metadata clients may use for the session
    /// presentation. The protocol does not interpret these values; producers
    /// SHOULD keep the payload small because summaries appear in session lists
    /// and session notifications.</summary>
    [JsonPropertyName("_meta")]
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public Dictionary<string, JsonElement>? Meta { get; set; }
}

/// <summary>Aggregate counts describing the file changes associated with a session.
///
/// All fields are optional so servers can populate only the metrics they
/// cheaply have available.</summary>
public sealed record ChangesSummary
{
    /// <summary>Total number of inserted lines across all changed files.</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public long? Additions { get; init; }

    /// <summary>Total number of deleted lines across all changed files.</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public long? Deletions { get; init; }

    /// <summary>Number of files that have changes.</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public long? Files { get; init; }
}

/// <summary>Server-owned project metadata for a session.</summary>
public sealed record ProjectInfo
{
    /// <summary>Project URI</summary>
    public required string Uri { get; init; }

    /// <summary>Human-readable project name</summary>
    public required string DisplayName { get; init; }
}

/// <summary>A session configuration property descriptor.
///
/// Extends the generic {@link ConfigPropertySchema} with session-specific
/// display extensions.</summary>
public sealed record SessionConfigPropertySchema
{
    /// <summary>JSON Schema: property type</summary>
    public required string Type { get; init; }

    /// <summary>JSON Schema: human-readable label for the property</summary>
    public required string Title { get; init; }

    /// <summary>JSON Schema: description / tooltip</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public string? Description { get; init; }

    /// <summary>JSON Schema: default value</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public JsonElement? Default { get; init; }

    /// <summary>JSON Schema: allowed values. May be primitives of any JSON type.</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public List<JsonElement>? Enum { get; init; }

    /// <summary>Display extension: human-readable label per enum value (parallel array)</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public List<string>? EnumLabels { get; init; }

    /// <summary>Display extension: description per enum value (parallel array)</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public List<string>? EnumDescriptions { get; init; }

    /// <summary>JSON Schema: when `true`, the property is displayed but cannot be modified by the user</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public bool? ReadOnly { get; init; }

    /// <summary>JSON Schema: schema for array items (used when `type` is `'array'`)</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public ConfigPropertySchema? Items { get; init; }

    /// <summary>JSON Schema: property descriptors for object properties (used when `type` is `'object'`)</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public Dictionary<string, ConfigPropertySchema>? Properties { get; init; }

    /// <summary>JSON Schema: list of required property ids (used when `type` is `'object'`)</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public List<string>? Required { get; init; }

    /// <summary>JSON Schema: schema for additional properties not listed in `properties` (used when `type` is `'object'`).</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public ConfigPropertySchema? AdditionalProperties { get; init; }

    /// <summary>Display extension: when `true`, the full set of allowed values is too large
    /// to enumerate statically. The client SHOULD use `sessionConfigCompletions`
    /// to fetch matching values based on user input. Any values in `enum` are
    /// seed/recent values for initial display.</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public bool? EnumDynamic { get; init; }

    /// <summary>When `true`, the user may change this property after session creation</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public bool? SessionMutable { get; init; }
}

/// <summary>A JSON Schema object describing available session configuration metadata.</summary>
public sealed record SessionConfigSchema
{
    /// <summary>JSON Schema: always `'object'`</summary>
    public required string Type { get; init; }

    /// <summary>JSON Schema: property descriptors keyed by property id</summary>
    public required Dictionary<string, SessionConfigPropertySchema> Properties { get; init; }

    /// <summary>JSON Schema: list of required property ids</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public List<string>? Required { get; init; }
}

/// <summary>Live session configuration metadata.
///
/// The schema describes the available configuration properties and the values
/// contain the current value for each resolved property.</summary>
public sealed class SessionConfigState
{
    /// <summary>JSON Schema describing available configuration properties</summary>
    public required SessionConfigSchema Schema { get; set; }

    /// <summary>Current configuration values</summary>
    public required Dictionary<string, JsonElement> Values { get; set; }
}

/// <summary>A completed request/response cycle.</summary>
public sealed class Turn
{
    /// <summary>Turn identifier</summary>
    public required string Id { get; set; }

    /// <summary>The message that initiated the turn</summary>
    public required Message Message { get; set; }

    /// <summary>All response content in stream order: text, tool calls, reasoning, and content refs.
    ///
    /// Consumers should derive display text by concatenating markdown parts,
    /// and find tool calls by filtering for `ToolCall` parts.</summary>
    public required List<ResponsePart> ResponseParts { get; set; }

    /// <summary>Token usage info</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public UsageInfo? Usage { get; set; }

    /// <summary>How the turn ended</summary>
    public TurnState State { get; set; }

    /// <summary>Error details if state is `'error'`</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public ErrorInfo? Error { get; set; }
}

/// <summary>An in-progress turn — the assistant is actively streaming.</summary>
public sealed class ActiveTurn
{
    /// <summary>Turn identifier</summary>
    public required string Id { get; set; }

    /// <summary>The message that initiated the turn</summary>
    public required Message Message { get; set; }

    /// <summary>All response content in stream order: text, tool calls, reasoning, and content refs.
    ///
    /// Tool call parts include `pendingPermissions` when permissions are awaiting user approval.</summary>
    public required List<ResponsePart> ResponseParts { get; set; }

    /// <summary>Token usage info</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public UsageInfo? Usage { get; set; }
}

/// <summary>Identifies the origin of a {@link Message} — who produced it. For the message
/// that initiates a turn ({@link Turn.message}), this is also the origin of the
/// turn; for steering or queued messages it is just the origin of that message.</summary>
public sealed record MessageOrigin
{
    /// <summary>The kind of actor that produced the message.</summary>
    public MessageKind Kind { get; init; }
}

/// <summary>A message that initiates or steers a turn. Messages can originate from the
/// user, the agent, a tool, or be system-generated (see {@link MessageOrigin}).
///
/// Attachments MAY be referenced inside {@link Message.text} via their
/// {@link MessageAttachmentBase.range} field. Attachments without a range are
/// still associated with the message but do not correspond to a specific span
/// in the text.</summary>
public sealed class Message
{
    /// <summary>Message text</summary>
    public required string Text { get; set; }

    /// <summary>The origin of the message</summary>
    public required MessageOrigin Origin { get; set; }

    /// <summary>File/selection attachments</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public List<MessageAttachment>? Attachments { get; set; }

    /// <summary>The model this message was, or will be, sent with.
    ///
    /// For historic user/agent messages this records the model actually used, so
    /// a client editing or resending the message can retain that selection. For a
    /// {@link ChatState.draft | draft} it carries the model the user picked for
    /// the message they are composing. Absent means the agent host's default
    /// model applies.</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public ModelSelection? Model { get; set; }

    /// <summary>The custom agent this message was, or will be, sent with.
    ///
    /// For historic messages this records the agent actually used; for a
    /// {@link ChatState.draft | draft} it carries the agent the user picked.
    /// Absent means no custom agent — the provider's default behavior applies.</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public AgentSelection? Agent { get; set; }

    /// <summary>Additional provider-specific metadata for this message.
    ///
    /// Clients MAY look for well-known keys here to provide enhanced UI, and
    /// agent hosts MAY use it to carry context that does not fit any other
    /// field. Mirrors the MCP `_meta` convention.</summary>
    [JsonPropertyName("_meta")]
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public Dictionary<string, JsonElement>? Meta { get; set; }
}

/// <summary>A zero-based position within a textual document.</summary>
public sealed record TextPosition
{
    /// <summary>Zero-based line number.</summary>
    public long Line { get; init; }

    /// <summary>Zero-based character offset within the line.</summary>
    public long Character { get; init; }
}

/// <summary>A range within a textual document.</summary>
public sealed record TextRange
{
    /// <summary>Start position of the range.</summary>
    public required TextPosition Start { get; init; }

    /// <summary>End position of the range.</summary>
    public required TextPosition End { get; init; }
}

/// <summary>A selection within a textual resource.
///
/// This is only meaningful for textual resources. Binary resources may still
/// use resource or embedded resource attachments, but they should not use this
/// text selection field.</summary>
public sealed record TextSelection
{
    /// <summary>The range covered by the selection.</summary>
    public required TextRange Range { get; init; }
}

/// <summary>A simple, opaque attachment whose model representation is described by
/// the producer.</summary>
public sealed record SimpleMessageAttachment
{
    /// <summary>A human-readable label for the attachment (e.g. the filename of a file
    /// attachment). Used for display in UI.</summary>
    public required string Label { get; init; }

    /// <summary>If defined, the range in {@link Message.text} that references this
    /// attachment. This is a text range, not a byte range.</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public TextRange? Range { get; init; }

    /// <summary>Advisory display hint for clients rendering this attachment. Recognized
    /// values include:
    ///
    /// - `'image'`: the attachment is an image
    /// - `'document'`: the attachment is a textual document
    /// - `'symbol'`: the attachment is a code symbol (e.g. a function or class)
    /// - `'directory'`: the attachment is a folder
    /// - `'selection'`: the attachment is a selection within a document
    ///
    /// Implementations MAY provide additional values; clients SHOULD fall back
    /// to a reasonable default when an unknown value is encountered.</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public string? DisplayKind { get; init; }

    /// <summary>Additional implementation-defined metadata for the attachment.
    ///
    /// If the attachment was produced by the `completions` command, the client
    /// MUST preserve every property of `_meta` originally returned by the agent
    /// host when sending the user message containing the accepted completion.</summary>
    [JsonPropertyName("_meta")]
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public Dictionary<string, JsonElement>? Meta { get; init; }

    /// <summary>Discriminant</summary>
    public MessageAttachmentKind Type { get; init; }

    /// <summary>Representation of the attachment as it should be shown to the model.
    ///
    /// If the attachment was produced by the client, this property MUST be
    /// defined so the agent host can correctly interpret the attachment. This
    /// property MAY be omitted when the attachment originated from a
    /// `completions` response.</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public string? ModelRepresentation { get; init; }
}

/// <summary>An attachment whose data is embedded inline as a base64 string.
///
/// Use this for small binary payloads (e.g. a pasted image) that should be
/// delivered with the user message itself rather than fetched separately.</summary>
public sealed record MessageEmbeddedResourceAttachment
{
    /// <summary>A human-readable label for the attachment (e.g. the filename of a file
    /// attachment). Used for display in UI.</summary>
    public required string Label { get; init; }

    /// <summary>If defined, the range in {@link Message.text} that references this
    /// attachment. This is a text range, not a byte range.</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public TextRange? Range { get; init; }

    /// <summary>Advisory display hint for clients rendering this attachment. Recognized
    /// values include:
    ///
    /// - `'image'`: the attachment is an image
    /// - `'document'`: the attachment is a textual document
    /// - `'symbol'`: the attachment is a code symbol (e.g. a function or class)
    /// - `'directory'`: the attachment is a folder
    /// - `'selection'`: the attachment is a selection within a document
    ///
    /// Implementations MAY provide additional values; clients SHOULD fall back
    /// to a reasonable default when an unknown value is encountered.</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public string? DisplayKind { get; init; }

    /// <summary>Additional implementation-defined metadata for the attachment.
