public sealed class MarkdownResponsePart
{
    /// <summary>Discriminant</summary>
    public ResponsePartKind Kind { get; set; }

    /// <summary>Part identifier, used by `chat/delta` to target this part for content appends</summary>
    public required string Id { get; set; }

    /// <summary>Markdown content</summary>
    public required string Content { get; set; }
}

/// <summary>A reference to large content stored outside the state tree.</summary>
public sealed record ContentRef
{
    /// <summary>Content URI</summary>
    public required string Uri { get; init; }

    /// <summary>Approximate size in bytes</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public long? SizeHint { get; init; }

    /// <summary>Content MIME type</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public string? ContentType { get; init; }
}

/// <summary>A content part that's a reference to large content stored outside the state tree.</summary>
public sealed record ResourceResponsePart
{
    /// <summary>Content URI</summary>
    public required string Uri { get; init; }

    /// <summary>Approximate size in bytes</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public long? SizeHint { get; init; }

    /// <summary>Content MIME type</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public string? ContentType { get; init; }

    /// <summary>Discriminant</summary>
    public ResponsePartKind Kind { get; init; }
}

/// <summary>A tool call represented as a response part.
///
/// Tool calls are part of the response stream, interleaved with text and
/// reasoning. The `toolCall.toolCallId` serves as the part identifier for
/// actions that target this part.</summary>
public sealed class ToolCallResponsePart
{
    /// <summary>Discriminant</summary>
    public ResponsePartKind Kind { get; set; }

    /// <summary>Full tool call lifecycle state</summary>
    public required ToolCallState ToolCall { get; set; }
}

/// <summary>Reasoning/thinking content from the model.</summary>
public sealed class ReasoningResponsePart
{
    /// <summary>Discriminant</summary>
    public ResponsePartKind Kind { get; set; }

    /// <summary>Part identifier, used by `chat/reasoning` to target this part for content appends</summary>
    public required string Id { get; set; }

    /// <summary>Accumulated reasoning text</summary>
    public required string Content { get; set; }
}

/// <summary>A system notification surfaced as part of the response stream.
///
/// System notifications are messages authored by the agent harness
/// that need to be visible to both the agent (for situational awareness) and
/// the user (for transcript continuity). Examples include "background subagent
/// X completed" or "task Y was cancelled".</summary>
public sealed record SystemNotificationResponsePart
{
    /// <summary>Discriminant</summary>
    public ResponsePartKind Kind { get; init; }

    /// <summary>The text of the system notification</summary>
    public required StringOrMarkdown Content { get; init; }
}

/// <summary>Tool execution result details, available after execution completes.</summary>
public sealed record ToolCallResult
{
    /// <summary>Whether the tool succeeded</summary>
    public bool Success { get; init; }

    /// <summary>Past-tense description of what the tool did</summary>
    public required StringOrMarkdown PastTenseMessage { get; init; }

    /// <summary>Unstructured result content blocks.
    ///
    /// This mirrors the `content` field of MCP `CallToolResult`.</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public List<ToolResultContent>? Content { get; init; }

    /// <summary>Optional structured result object.
    ///
    /// This mirrors the `structuredContent` field of MCP `CallToolResult`.</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public Dictionary<string, JsonElement>? StructuredContent { get; init; }

    /// <summary>Error details if the tool failed</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public JsonElement? Error { get; init; }
}

/// <summary>A confirmation option that the server offers for a tool call awaiting
/// approval. Allows richer choices beyond simple approve/deny — for example,
/// "Approve in this Session" or "Deny with reason."</summary>
public sealed record ConfirmationOption
{
    /// <summary>Unique identifier for the option, returned in the confirmed action</summary>
    public required string Id { get; init; }

    /// <summary>Human-readable label displayed to the user</summary>
    public required string Label { get; init; }

    /// <summary>Whether this option represents an approval or denial</summary>
    public ConfirmationOptionKind Kind { get; init; }

    /// <summary>Logical group number for visual categorisation.
    ///
    /// Clients SHOULD display options in the order they are defined and MAY
    /// use differing group numbers to insert dividers between logical clusters
    /// of options.</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public long? Group { get; init; }
}

/// <summary>LM is streaming the tool call parameters.</summary>
public sealed class ToolCallStreamingState
{
    /// <summary>Unique tool call identifier</summary>
    public required string ToolCallId { get; set; }

    /// <summary>Internal tool name (for debugging/logging)</summary>
    public required string ToolName { get; set; }

    /// <summary>Human-readable tool name</summary>
    public required string DisplayName { get; set; }

    /// <summary>Reference to the contributor of the tool being called.</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public ToolCallContributor? Contributor { get; set; }

    /// <summary>Additional provider-specific metadata for this tool call.
    ///
    /// This MAY include a `ui` field corresponding to the MCP Apps (SEP-1865)
    /// `McpUiToolMeta` found in MCP tool calls, which may be used in combination
    /// with the {@link contributor} to serve MCP Apps.</summary>
    [JsonPropertyName("_meta")]
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public Dictionary<string, JsonElement>? Meta { get; set; }

    public ToolCallStatus Status { get; set; }

    /// <summary>Partial parameters accumulated so far</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public string? PartialInput { get; set; }

    /// <summary>Progress message shown while parameters are streaming</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public StringOrMarkdown? InvocationMessage { get; set; }
}

/// <summary>Parameters are complete, or a running tool requires re-confirmation
/// (e.g. a mid-execution permission check).</summary>
public sealed record ToolCallPendingConfirmationState
{
    /// <summary>Unique tool call identifier</summary>
    public required string ToolCallId { get; init; }

