/// declaration's span.
///
/// The MCP server customization also reflects its current status.</summary>
public sealed class McpServerCustomization
{
    /// <summary>Session-unique opaque identifier. Used by every action that targets a
    /// specific customization. Minted by whoever publishes the customization
    /// (typically the agent host).</summary>
    public required string Id { get; set; }

    /// <summary>Source URI for this customization. A plugin URL, a file URI, or a
    /// directory URI.
    ///
    /// For declarations that live inside a larger file — e.g. an MCP
    /// server declared inline in a `plugins.json` manifest — `uri` points
    /// to the containing file and {@link CustomizationBase.range | `range`}
    /// narrows it to the declaration's span.</summary>
    public required string Uri { get; set; }

    /// <summary>Human-readable name.</summary>
    public required string Name { get; set; }

    /// <summary>Icons for UI display.</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public List<Icon>? Icons { get; set; }

    /// <summary>Optional span within {@link CustomizationBase.uri | `uri`} when this
    /// customization is a subset of a larger file (for example, one entry
    /// in an inline `mcpServers` block of a `plugins.json` manifest).
    /// Absent when the customization covers the whole resource.</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public TextRange? Range { get; set; }

    public CustomizationType Type { get; set; }

