/// <summary>Full state for a single terminal, loaded when a client subscribes to the terminal's URI.</summary>
public sealed class TerminalState
{
    /// <summary>Human-readable terminal title</summary>
    public required string Title { get; set; }

    /// <summary>Current working directory of the terminal process</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public string? Cwd { get; set; }

    /// <summary>Terminal width in columns</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public long? Cols { get; set; }

    /// <summary>Terminal height in rows</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public long? Rows { get; set; }

    /// <summary>Typed content parts, replacing the flat `content: string`.
    ///
    /// Naive consumers that only need the raw VT stream can reconstruct it with:
    ///   `content.map(p =&gt; p.type === 'command' ? p.output : p.value).join('')`
    ///
    /// Consumers that need command boundaries can filter by part type.</summary>
    public required List<TerminalContentPart> Content { get; set; }

    /// <summary>Process exit code, set when the terminal process exits</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public long? ExitCode { get; set; }

    /// <summary>Who currently holds this terminal</summary>
    public required TerminalClaim Claim { get; set; }

    /// <summary>Whether this terminal emits `terminal/commandExecuted` and
    /// `terminal/commandFinished` actions and populates `command`-typed parts.
    ///
    /// Clients MUST check this flag before relying on command detection.
    /// Do NOT use the presence of a `command` part as a feature flag — parts
    /// are absent in the normal idle state.</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public bool? SupportsCommandDetection { get; set; }
}

/// <summary>Unstructured terminal output — content before, between, or after commands,
/// or from terminals that do not support command detection.</summary>
public sealed class TerminalUnclassifiedPart
{
    public required string Type { get; set; }

    /// <summary>Accumulated VT output. Appended to by `terminal/data` when no command is executing.</summary>
    public required string Value { get; set; }
}

/// <summary>A single command: its command line and the output it produced.
///
/// While `isComplete` is false the command is still executing; `output` grows
/// as `terminal/data` actions arrive. At `terminal/commandFinished` the part
/// is mutated in-place with `isComplete: true` and the completion metadata.</summary>
public sealed class TerminalCommandPart
{
    public required string Type { get; set; }

    /// <summary>Stable id matching the `commandId` on the corresponding
    /// `terminal/commandExecuted` and `terminal/commandFinished` actions.</summary>
    public required string CommandId { get; set; }

    /// <summary>The command line submitted to the shell.</summary>
    public required string CommandLine { get; set; }

    /// <summary>Accumulated VT output. Appended to by `terminal/data` while `isComplete`
    /// is false. Shell integration escape sequences are stripped by the server.</summary>
    public required string Output { get; set; }

    /// <summary>Unix timestamp (ms) when execution started, as reported by the server.</summary>
    public long Timestamp { get; set; }

    /// <summary>Whether the command has finished.</summary>
    public bool IsComplete { get; set; }

    /// <summary>Shell exit code. Set at completion. `undefined` if unknown.</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public long? ExitCode { get; set; }

    /// <summary>Wall-clock duration in milliseconds. Set at completion.</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public long? DurationMs { get; set; }
}

