/// <summary>A point-in-time snapshot of a subscribed resource's state, returned by
/// `initialize`, `reconnect`, and `subscribe`.</summary>
public sealed record Snapshot
{
    /// <summary>The subscribed channel URI (e.g. `ahp-root://`, `ahp-session:/&lt;uuid&gt;`, or `ahp-chat:/&lt;uuid&gt;`)</summary>
    public required string Resource { get; init; }

    /// <summary>The current state of the resource</summary>
    public required SnapshotState State { get; init; }

    /// <summary>The `serverSeq` at which this snapshot was taken. Subsequent actions will have `serverSeq &gt; fromSeq`.</summary>
    public long FromSeq { get; init; }
}

/// <summary>Catalogue entry describing one changeset the server can produce for a
/// session.
///
/// Catalogue entries are intentionally lightweight — just enough to render a
/// chip or list row without subscribing. Full per-changeset detail
/// ({@link ChangesetState}) lives on the subscribable URI obtained by
/// expanding {@link uriTemplate}.</summary>
public sealed record Changeset
{
    /// <summary>Human-readable label, e.g. `"Uncommitted Changes"`.</summary>
    public required string Label { get; init; }

    /// <summary>RFC 6570 URI template. Clients parse the variables directly out of the
    /// template using the standard `{name}` syntax — they are not redeclared
    /// here.
    ///
    /// Only the following template shapes are defined by this protocol; any
    /// other variable name MUST be ignored by clients (there is no
    /// protocol-defined way to obtain values for unknown variables):
    ///
    /// | Variables in template                       | Meaning                                                                              |
    /// | ------------------------------------------- | ------------------------------------------------------------------------------------ |
    /// | _(none)_                                    | A static, session-wide changeset. The template is itself a subscribable URI.         |
    /// | `{turnId}`                                  | Per-turn slice. Expand with a `Turn.id` from the session.                            |
    /// | `{originalTurnId}` and `{modifiedTurnId}`   | Diff between two turns. Both variables MUST be present.                              |
    ///
    /// Future protocol versions MAY add new well-known variables.</summary>
    public required string UriTemplate { get; init; }

    /// <summary>Optional longer description.</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public string? Description { get; init; }

    /// <summary>Advisory hint describing what kind of changeset this is, so clients can
    /// group, sort, or render an appropriate icon without parsing
    /// {@link uriTemplate}. Recognized values include:
    ///
    /// - `'session'`: a static, session-wide changeset covering all changes the
    ///   agent has produced in this session.
    /// - `'branch'`: changes relative to a base branch (e.g. a feature branch
    ///   diffed against `main`).
    /// - `'uncommitted'`: the workspace's current uncommitted changes.
    /// - `'turn'`: changes produced by a single turn. Typically paired with a
    ///   `{turnId}` variable in {@link uriTemplate}.
    /// - `'compare-turns'`: a diff between two turns. Typically paired with
    ///   `{originalTurnId}` and `{modifiedTurnId}` variables in
    ///   {@link uriTemplate}.
    ///
    /// Implementations MAY provide additional values; clients SHOULD fall back
    /// to a reasonable default when an unknown value is encountered.</summary>
    public required string ChangeKind { get; init; }
}

/// <summary>Full state for a single changeset, returned when a client subscribes to
/// an expanded changeset URI.
///
/// The client already knows the URI it subscribed to, so this state does
/// not redundantly carry it (or the catalogue's `id`, `label`, etc.).
/// Aggregate counts (`additions`, `deletions`, `files`) are likewise
/// omitted: clients trivially compute them from `files[].edit.diff`.</summary>
public sealed class ChangesetState
{
    /// <summary>Computation lifecycle.</summary>
    public ChangesetStatus Status { get; set; }

    /// <summary>Present iff `status === ChangesetStatus.Error`.</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public ErrorInfo? Error { get; set; }

    /// <summary>Files in this changeset, keyed by {@link ChangesetFile.id}.</summary>
    public required List<ChangesetFile> Files { get; set; }

    /// <summary>Operations the client may invoke against this changeset. Omit when no
    /// operations are available.</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public List<ChangesetOperation>? Operations { get; set; }
}

/// <summary>One file entry within a {@link ChangesetState}.</summary>
public sealed record ChangesetFile
{
    /// <summary>Stable identifier within the changeset. Typically `after.uri`
    /// (or `before.uri` for deletions).</summary>
    public required string Id { get; init; }

    /// <summary>Reuses the existing {@link FileEdit} shape. Clients derive line
    /// additions, deletions, and rename/create/delete semantics from this.</summary>
    public required FileEdit Edit { get; init; }

    /// <summary>Server-defined opaque metadata, surfaced to operations and tooling
    /// but not interpreted by the protocol.</summary>
    [JsonPropertyName("_meta")]
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public Dictionary<string, JsonElement>? Meta { get; init; }
}

/// <summary>A server-declared invokable verb the client can run against a
/// changeset, a file, or a range — `"stage"`, `"revert"`, `"create-pr"`,
/// and so on.
///
/// The term "operation" is used deliberately to avoid colliding with the
/// protocol-level [Actions](/guide/actions) that mutate state.</summary>
public sealed class ChangesetOperation
{
    /// <summary>Stable identifier, unique within this changeset.</summary>
    public required string Id { get; set; }

    /// <summary>Human-readable button/menu label.</summary>
    public required string Label { get; set; }

    /// <summary>Optional longer description shown on hover or in tooltips.</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public string? Description { get; set; }

    /// <summary>Where this operation can be invoked.</summary>
    public required List<ChangesetOperationScope> Scopes { get; set; }

    /// <summary>Optional confirmation prompt to show before invoking. When present,
    /// the client MUST display this message to the user (typically in a
    /// confirmation dialog) and only invoke the operation after the user
    /// accepts. The presence of this field also signals that the operation
    /// is destructive — clients SHOULD style the affirmative button
    /// accordingly (e.g. with a warning colour).</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public StringOrMarkdown? Confirmation { get; set; }

    /// <summary>Optional generic icon hint, e.g. `"check"`, `"trash"`.</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public string? Icon { get; set; }

    /// <summary>Optional group identifier, used to group related operations together.</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public string? Group { get; set; }

    /// <summary>Current execution status. The server sets
    /// {@link ChangesetOperationStatus.Running | Running} while an invocation
    /// is in flight, {@link ChangesetOperationStatus.Error | Error} when the
    /// most recent invocation failed, and
    /// {@link ChangesetOperationStatus.Idle | Idle} otherwise.
    ///
    /// Clients SHOULD reflect this state in the UI — e.g. disabling the
    /// control or showing a spinner while `Running`, and surfacing
    /// {@link error} while `Error`.</summary>
    public ChangesetOperationStatus Status { get; set; }

    /// <summary>Cause of failure. Present iff
    /// `status === ChangesetOperationStatus.Error`; otherwise omitted.</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public ErrorInfo? Error { get; set; }
}

/// <summary>OTLP telemetry channels the agent host emits.
///
/// Each field, when present, is either a literal channel URI or an
/// [RFC 6570](https://datatracker.ietf.org/doc/html/rfc6570) URI template
/// a client expands and then subscribes to. Absent fields indicate the host
/// does not emit that signal.
///
/// Channel URIs use the `ahp-otlp:` scheme. The scheme identifies the
/// protocol (OpenTelemetry over AHP) so clients can recognise the channel
/// type by URI alone; the host is free to choose any authority/path that
/// makes sense for its implementation. Clients MUST treat the URI as
/// opaque (apart from expanding any well-known template variables defined
/// below) and subscribe with the resulting concrete URI.
///
/// Payloads delivered on these channels are OTLP/JSON values — see
/// [opentelemetry-proto](https://github.com/open-telemetry/opentelemetry-proto)
/// for the wire shapes (`ExportLogsServiceRequest`,
/// `ExportTraceServiceRequest`, `ExportMetricsServiceRequest`).</summary>
public sealed record TelemetryCapabilities
{
    /// <summary>Channel URI (or RFC 6570 URI template) for OTLP log records
    /// (`otlp/exportLogs` notifications).
    ///
    /// The following template variables are defined by this protocol; any
    /// other variable name MUST be ignored by clients (there is no
    /// protocol-defined way to obtain values for unknown variables):
    ///
    /// | Variables in template | Meaning                                                                                                 |
    /// | --------------------- | ------------------------------------------------------------------------------------------------------- |
    /// | _(none)_              | The host does not support subscriber-side severity filtering. The template is itself a subscribable URI. |
    /// | `{level}`             | Minimum OTLP severity to deliver. Expand to one of the [OTLP `SeverityNumber`](https://opentelemetry.io/docs/specs/otel/logs/data-model/#field-severitynumber) short names (case-insensitive): `trace`, `debug`, `info`, `warn`, `error`, `fatal`. The server delivers log records whose `severityNumber` falls in the corresponding band or above. |
    ///
    /// Hosts SHOULD honour the expanded `{level}`; clients MUST still filter
    /// defensively in case a host ignores the parameter. Hosts that do not
    /// advertise `{level}` deliver all severities.
    ///
    /// Future protocol versions MAY add new well-known variables (e.g. scope
    /// or attribute filters).</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public string? Logs { get; init; }

    /// <summary>Channel URI for OTLP spans (`otlp/exportTraces` notifications). No
    /// template variables are defined by this protocol version.</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public string? Traces { get; init; }

    /// <summary>Channel URI for OTLP metric data points (`otlp/exportMetrics`
    /// notifications). No template variables are defined by this protocol
    /// version.</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public string? Metrics { get; init; }
}

/// <summary>Full state for a single resource watch, returned when a client subscribes
/// to an `ahp-resource-watch:` URI.
///
/// Watches are otherwise stateless: the watcher exists to deliver
/// {@link ResourceWatchChangedAction} events. The state carries only the
/// descriptor of what is being watched so a re-subscribing client can
/// recover the watch configuration after reconnecting.</summary>
public sealed record ResourceWatchState
{
    /// <summary>The URI being watched. For recursive watches this is the root of the
    /// subtree; for non-recursive watches this is the single file or
    /// directory.</summary>
    public required string Root { get; init; }

    /// <summary>`true` if the watcher reports changes for descendants of `root`;
    /// `false` if it only reports changes to `root` itself (and, when
    /// `root` is a directory, its direct children).</summary>
    public bool Recursive { get; init; }

    /// <summary>Optional glob patterns or paths relative to `root` to exclude from
    /// change reporting.</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public JsonElement? Excludes { get; init; }

    /// <summary>Optional glob patterns or paths relative to `root` to restrict
    /// change reporting to. Omit to report every change under `root`
    /// subject to `excludes`.</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public JsonElement? Includes { get; init; }
}

/// <summary>A single change observed by a resource watcher.</summary>
public sealed record ResourceChange
{
    /// <summary>The URI of the resource that changed.</summary>
    public required string Uri { get; init; }

    /// <summary>The kind of change observed.</summary>
    public ResourceChangeType Type { get; init; }
}

/// <summary>Lightweight per-session summary of the annotations channel, surfaced on
/// {@link SessionSummary.annotations} so badge UI can render annotation /
/// entry counts without subscribing to the channel itself.</summary>
public sealed record AnnotationsSummary
{
    /// <summary>The subscribable annotations channel URI for the owning session
    /// (typically `ahp-session:/&lt;uuid&gt;/annotations`). Surfaced explicitly even
    /// though it is derivable from the session URI so badge UI does not need
    /// to know the derivation rule.</summary>
    public required string Resource { get; init; }

    /// <summary>Total number of {@link Annotation} entries in the channel.</summary>
    public long AnnotationCount { get; init; }

    /// <summary>Total number of {@link AnnotationEntry} entries across every annotation.</summary>
    public long EntryCount { get; init; }
}

/// <summary>Full state for a session's annotations channel, returned when a client
/// subscribes to an `ahp-session:/&lt;uuid&gt;/annotations` URI.</summary>
public sealed record AnnotationsState
{
    /// <summary>Annotations in this channel, keyed by {@link Annotation.id}.</summary>
    public required List<Annotation> Annotations { get; init; }
}

/// <summary>A conversation anchored to a specific file produced by a specific turn,
/// optionally narrowed to a range within that file.
///
/// {@link turnId} anchors the annotation to the file versions that turn
/// produced, so a later turn that rewrites the same file does not silently
/// invalidate the annotation's anchor — clients can resolve {@link resource}
/// and {@link range} against the turn's changeset. When {@link range} is
/// omitted the annotation is anchored to the entire file.
///
/// Every annotation MUST contain at least one {@link AnnotationEntry}. An
/// {@link AnnotationsSetAction} that creates an annotation therefore carries
/// its mandatory first entry, and removing the last remaining entry collapses
/// the annotation via {@link AnnotationsRemovedAction} rather than leaving an
/// empty annotation behind.</summary>
public sealed record Annotation
{
    /// <summary>Stable identifier within the annotations channel. Assigned by the client
    /// that dispatches the creating {@link AnnotationsSetAction}.</summary>
    public required string Id { get; init; }

    /// <summary>Turn that produced the file versions this annotation is anchored to.
    /// Matches a {@link Turn.id} on the owning session.</summary>
    public required string TurnId { get; init; }

    /// <summary>The file the annotation is anchored to.</summary>
    public required string Resource { get; init; }

    /// <summary>Range within {@link resource} the annotation is anchored to. When
    /// omitted the annotation is anchored to the entire file.</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public TextRange? Range { get; init; }

    /// <summary>Whether the annotation has been resolved. Newly created annotations are
    /// always unresolved (`false`); a client marks an annotation resolved (or
    /// re-opens it) by dispatching an {@link AnnotationsUpdatedAction} carrying
    /// the updated flag (or an {@link AnnotationsSetAction} when replacing the
    /// whole annotation).</summary>
    public bool Resolved { get; init; }

    /// <summary>Entries in this annotation, in dispatch order (oldest first). MUST
    /// contain at least one entry.</summary>
    public required List<AnnotationEntry> Entries { get; init; }

    /// <summary>Producer-defined opaque metadata, surfaced to tooling but not
    /// interpreted by the protocol.</summary>
    [JsonPropertyName("_meta")]
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public Dictionary<string, JsonElement>? Meta { get; init; }
}

/// <summary>A single entry within an {@link Annotation}.</summary>
public sealed record AnnotationEntry
{
    /// <summary>Stable identifier within the enclosing annotation. Assigned by the client
    /// that dispatches the {@link AnnotationsEntrySetAction} (or the enclosing
    /// {@link AnnotationsSetAction}) introducing the entry.</summary>
    public required string Id { get; init; }

    /// <summary>Entry body. A bare `string` is rendered as plain text; pass
    /// `{ markdown: "…" }` to opt into Markdown rendering. See
    /// {@link StringOrMarkdown}.</summary>
    public required StringOrMarkdown Text { get; init; }

    /// <summary>Producer-defined opaque metadata, surfaced to tooling but not
    /// interpreted by the protocol.</summary>
    [JsonPropertyName("_meta")]
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public Dictionary<string, JsonElement>? Meta { get; init; }
}

