// ─── Discriminated Unions ─────────────────────────────────────────────

/// <summary>ResponsePart is a single part of a response stream (text, tool call, reasoning, content reference).</summary>
[JsonConverter(typeof(ResponsePartConverter))]
public sealed class ResponsePart : AhpUnion
{
    /// <summary>Creates an empty ResponsePart (no active variant).</summary>
    public ResponsePart() { }

    /// <summary>Creates a ResponsePart wrapping the given variant value.</summary>
    public ResponsePart(object? value) : base(value) { }
}

/// <summary>System.Text.Json converter for the ResponsePart discriminated union.</summary>
internal sealed class ResponsePartConverter : UnionConverter<ResponsePart>
{
    public ResponsePartConverter()
        : base(
            discriminator: "kind",
            variants: new Dictionary<string, Type>
            {
        ["markdown"] = typeof(MarkdownResponsePart),
        ["contentRef"] = typeof(ResourceResponsePart),
        ["toolCall"] = typeof(ToolCallResponsePart),
        ["reasoning"] = typeof(ReasoningResponsePart),
        ["systemNotification"] = typeof(SystemNotificationResponsePart),
            },
            allowUnknown: true)
    {
    }
}

/// <summary>ToolCallState is the full tool call lifecycle state.</summary>
[JsonConverter(typeof(ToolCallStateConverter))]
public sealed class ToolCallState : AhpUnion
{
    /// <summary>Creates an empty ToolCallState (no active variant).</summary>
    public ToolCallState() { }

    /// <summary>Creates a ToolCallState wrapping the given variant value.</summary>
    public ToolCallState(object? value) : base(value) { }
}

/// <summary>System.Text.Json converter for the ToolCallState discriminated union.</summary>
internal sealed class ToolCallStateConverter : UnionConverter<ToolCallState>
{
    public ToolCallStateConverter()
        : base(
            discriminator: "status",
            variants: new Dictionary<string, Type>
            {
        ["streaming"] = typeof(ToolCallStreamingState),
        ["pending-confirmation"] = typeof(ToolCallPendingConfirmationState),
        ["running"] = typeof(ToolCallRunningState),
